import{_ as e,o as r,c as a,a2 as n}from"./chunks/framework.DvFsUg-r.js";const i="/assets/springboot-001.Bt2_QXUt.png",l="/assets/springboot101-28.D1VbxrJH.png",s="/assets/boot1.BoOViD9y.png",o="/assets/boot4.7dc5aVOu.png",d="/assets/boot5.Bhx-5NG8.png",g="/assets/springboot2.CcTbaHVl.png",u=JSON.parse('{"title":"1. SpringBoot Backend 서버 구축","description":"","frontmatter":{"title":"1. SpringBoot Backend 서버 구축","date":"2023-03-25T16:08:03.000Z","tags":["springboot"],"category":"Spring Boot","editLink":false,"lastUpdated":false},"headers":[],"relativePath":"blog-archive/coding/springboot/springboot101.md","filePath":"blog-archive/coding/springboot/springboot101.md"}'),c={name:"blog-archive/coding/springboot/springboot101.md"};function p(b,t,x,h,y,m){return r(),a("div",null,[...t[0]||(t[0]=[n('<p><img src="'+i+'" alt=""></p><h3 id="☁️-개요" tabindex="-1">☁️ 개요 <a class="header-anchor" href="#☁️-개요" aria-label="Permalink to &quot;☁️ 개요&quot;">​</a></h3><p>인텔리제이 springboot 개발환경을 구축하여 backend 프레임워크 구성을 진행 하고자 한다. 본 기술블로그에서 vue 관련 내용들을 정리 예정인데 backend framework는 springboot를 사용할 예정이다. jpa swagger mybatis 등 실무에서 사용하는 기술들에 대해 정리 예정이다.</p><h3 id="⬇️인텔리제이-설치" tabindex="-1">⬇️인텔리제이 설치 <a class="header-anchor" href="#⬇️인텔리제이-설치" aria-label="Permalink to &quot;⬇️인텔리제이 설치&quot;">​</a></h3><p>먼저 아래 사이트에서 인텔리제이 커뮤니티를 다운로드한다. 참고로 굳쎔은 Ultimate 버전을 구매해서 사용중이다. 나중에 vue.js를 코딩을 할때 ultimate 버전을 가지고 있다고 백엔드와 프론트 모두 한가지 ide로 할수 있어 여러모로 편리하다.</p><p><a href="https://www.jetbrains.com/ko-kr/idea/download/" target="_blank" rel="noreferrer">인텔리제이 다운로드</a></p><h3 id="📖-springboot-project-생성" tabindex="-1">📖 springboot project 생성 <a class="header-anchor" href="#📖-springboot-project-생성" aria-label="Permalink to &quot;📖 springboot project 생성&quot;">​</a></h3><p><a href="https://start.spring.io/" target="_blank" rel="noreferrer">spring starter</a> 사이트에서 spring 프로젝트를 생성함. 아래와 같이 설정을하고 GENERATE 버튼을 클릭하면 해당 설정되로 압축 파일이 생성 및 다운로드됨. 다운로드후 압축 파일 풀어서 적당한 위치에 옮겨 해당 디렉토리를 불러오면 설정완료</p><table tabindex="0"><thead><tr><th style="text-align:center;">구분</th><th style="text-align:center;">설정</th><th style="text-align:center;">비고</th></tr></thead><tbody><tr><td style="text-align:center;">Project</td><td style="text-align:center;">Gradle Project 선택</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Language</td><td style="text-align:center;">Java 선택</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Spring Boot</td><td style="text-align:center;">3.0.5 선택</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Group</td><td style="text-align:center;">io.github.goodsaem</td><td style="text-align:center;">GroupId는 프로젝트를 식별해 주는 고유값. <br> 각자의 도메인으로 설정함</td></tr><tr><td style="text-align:center;">Artifact</td><td style="text-align:center;">api</td><td style="text-align:center;">war 나 jar 파일을 만들때 사용되며 버전정보를 제외한 파일이름</td></tr><tr><td style="text-align:center;">Name</td><td style="text-align:center;">api</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Description</td><td style="text-align:center;">rest api</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Package name</td><td style="text-align:center;">io.github.goodsaem.api</td><td style="text-align:center;">각자 맞게 설정</td></tr><tr><td style="text-align:center;">Packaging</td><td style="text-align:center;">war</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">Java</td><td style="text-align:center;">17</td><td style="text-align:center;">안정버전을 선택</td></tr><tr><td style="text-align:center;">Dependencies</td><td style="text-align:center;">Lombok</td><td style="text-align:center;">getter 나 setter 등을 자동완성할때 사용</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">H2 Database</td><td style="text-align:center;">H2 db 사용</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">MariaDB Driver</td><td style="text-align:center;">maria db 연결</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">Spring JPA</td><td style="text-align:center;">Java Persistence API 로 객체 지향적으로 데이터를 관리</td></tr></tbody></table><p><img src="'+l+'" alt="springstarter"></p><p>openjdk 최신버전 설치방법은 아래 링크 참고할것 <a href="http://goodsaem.github.io/2023/03/24/coding/java/openjdk/" target="_blank" rel="noreferrer">mac에 oepnjdk 19.0.1 버전 설치방법</a></p><h3 id="☕-인텔리제이에서-프로젝트-오픈" tabindex="-1">☕ 인텔리제이에서 프로젝트 오픈 <a class="header-anchor" href="#☕-인텔리제이에서-프로젝트-오픈" aria-label="Permalink to &quot;☕ 인텔리제이에서 프로젝트 오픈&quot;">​</a></h3><p>압축 푼 디렉토리를 인테리제이에서 Open 한다. 오픈 후 먼저 프로젝트 SDK 선택및 프로젝트에서 컴파일할 java 버전을 지정한다.</p><p>폴더에서 우클릭 하여 아래 그림과 같이 Open Moudule Setttings 메뉴를 클릭한다. <img src="'+s+'" alt=""></p><hr><ol><li>SDKS 메뉴를 클릭한다.</li><li>+아이콘을 클릭한다.</li><li>open jdk 19 를 선택한다. <img src="'+o+'" alt=""></li></ol><hr><ol><li>프로젝트 메뉴를 선택한다.</li><li>jdk를 선택한다.</li><li>프로젝트 언어 레벨을 17로 맞춘다. <img src="'+d+'" alt=""></li></ol><hr><p>해당 과정이 끝나고 나면 build.gradle 에 정의되어 있는 라이브러리를 자동으로 불러 온다. 만약 라이브러리를 제되로 불러오지 않는다면 Gradle 메뉴를 클릭하고 <i class="fa-solid fa-rotate"></i> 아이콘을 클릭하여 필요한 모듈을 다시 불러온다. <img src="'+g+'" alt="인텔리제이에서 프로젝트 오픈"></p><h3 id="마무리" tabindex="-1"><i class="fa-solid fa-clover"></i> 마무리 <a class="header-anchor" href="#마무리" aria-label="Permalink to &quot;&lt;i class=&quot;fa-solid fa-clover&quot;&gt;&lt;/i&gt; 마무리&quot;">​</a></h3><p>여기까지 springboot + 인텔리제이 개발 환경을 셋팅했다. 이제 실제 springboot 를 통한 예제를 하나씩 실습해보면서 spring boot를 마스터 해보자.</p>',22)])])}const f=e(c,[["render",p]]);export{u as __pageData,f as default};
